import{_ as a,c as r,o as e,a1 as d}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"快速開始: 從零使用 Antigravity Tools | Antigravity-Manager","description":"學習 Antigravity Tools 的完整上手流程。從安裝設定到首次 API 呼叫，快速掌握本地閘道的核心使用方法。","frontmatter":{"title":"快速開始: 從零使用 Antigravity Tools | Antigravity-Manager","sidebarTitle":"從零跑起來","subtitle":"快速開始: 從零使用 Antigravity Tools","description":"學習 Antigravity Tools 的完整上手流程。從安裝設定到首次 API 呼叫，快速掌握本地閘道的核心使用方法。","order":1},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/start/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/start/index.md"}'),o={name:"zh-tw/lbjlaq/Antigravity-Manager/start/index.md"};function n(s,t,i,l,b,c){return e(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="快速開始" tabindex="-1">快速開始 <a class="header-anchor" href="#快速開始" aria-label="Permalink to &quot;快速開始&quot;">​</a></h1><p>本章節帶你從零開始使用 Antigravity Tools，完成從安裝到第一次成功呼叫 API 的完整流程。你會學到核心概念、帳號管理、資料備份，以及如何讓你的 AI 用戶端接入本地閘道。</p><h2 id="本章內容" tabindex="-1">本章內容 <a class="header-anchor" href="#本章內容" aria-label="Permalink to &quot;本章內容&quot;">​</a></h2><div class="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6"><a href="./getting-started/" class="block p-4 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-brand-500 dark:hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">Antigravity Tools 是什麼</h3><p class="text-sm text-gray-600 dark:text-gray-400">建立正確心智模型：本地閘道、協定相容、帳號池調度的核心概念與使用邊界。</p></a><a href="./installation/" class="block p-4 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-brand-500 dark:hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">安裝與升級</h3><p class="text-sm text-gray-600 dark:text-gray-400">桌面端最佳安裝路徑（brew / releases），以及常見系統攔截的處理方式。</p></a><a href="./first-run-data/" class="block p-4 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-brand-500 dark:hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">首次啟動必懂</h3><p class="text-sm text-gray-600 dark:text-gray-400">資料目錄、日誌、托盤與自動啟動，避免誤刪與不可逆遺失。</p></a><a href="./add-account/" class="block p-4 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-brand-500 dark:hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">新增帳號</h3><p class="text-sm text-gray-600 dark:text-gray-400">OAuth/Refresh Token 雙通道與最佳實踐，用最穩的方式建立帳號池。</p></a><a href="./backup-migrate/" class="block p-4 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-brand-500 dark:hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">帳號備份與遷移</h3><p class="text-sm text-gray-600 dark:text-gray-400">匯入/匯出、V1/DB 熱遷移，支援多機複用與伺服器部署場景。</p></a><a href="./proxy-and-first-client/" class="block p-4 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-brand-500 dark:hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">啟動反代並接入用戶端</h3><p class="text-sm text-gray-600 dark:text-gray-400">從啟動服務到外部用戶端成功呼叫，一次跑通驗證閉環。</p></a></div><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推薦順序</p><p>按照以下順序學習，可以最快速地上手 Antigravity Tools：</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 概念理解        →  2. 安裝軟體        →  3. 了解資料目錄</span></span>
<span class="line"><span>   getting-started      installation          first-run-data</span></span>
<span class="line"><span>        ↓                    ↓                      ↓</span></span>
<span class="line"><span>4. 新增帳號        →  5. 備份帳號        →  6. 啟動反代</span></span>
<span class="line"><span>   add-account          backup-migrate        proxy-and-first-client</span></span></code></pre></div><table tabindex="0"><thead><tr><th>步驟</th><th>課程</th><th>預計時間</th><th>你會學到</th></tr></thead><tbody><tr><td>1</td><td><a href="./getting-started/">概念理解</a></td><td>5 分鐘</td><td>什麼是本地閘道、為什麼需要帳號池</td></tr><tr><td>2</td><td><a href="./installation/">安裝軟體</a></td><td>3 分鐘</td><td>brew 安裝或手動下載，處理系統攔截</td></tr><tr><td>3</td><td><a href="./first-run-data/">了解資料目錄</a></td><td>5 分鐘</td><td>資料存在哪、日誌怎麼看、托盤操作</td></tr><tr><td>4</td><td><a href="./add-account/">新增帳號</a></td><td>10 分鐘</td><td>OAuth 授權或手動填寫 Refresh Token</td></tr><tr><td>5</td><td><a href="./backup-migrate/">備份帳號</a></td><td>5 分鐘</td><td>匯出帳號、跨裝置遷移</td></tr><tr><td>6</td><td><a href="./proxy-and-first-client/">啟動反代</a></td><td>10 分鐘</td><td>啟動服務、設定用戶端、驗證呼叫</td></tr></tbody></table><p><strong>最小可用路徑</strong>：如果你趕時間，可以只完成 1 → 2 → 4 → 6，大約 25 分鐘即可開始使用。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，你已經可以正常使用 Antigravity Tools 了。接下來可以根據需要深入學習：</p><ul><li><strong><a href="./../platforms/">平台與整合</a></strong>：了解 OpenAI、Anthropic、Gemini 等不同協定的接入細節</li><li><strong><a href="./../advanced/">進階設定</a></strong>：模型路由、配額保護、高可用調度等進階功能</li><li><strong><a href="./../faq/">常見問題</a></strong>：遇到 401、429、404 等錯誤時的排查指南</li></ul>`,12)])])}const p=a(o,[["render",n]]);export{g as __pageData,p as default};
